def validate_label(label: str) -> Tuple[bool, str]:
    """Strictly validate that a label is in the allowed set."""
    if not isinstance(label, str):
        return False, "Label must be a string"
    label_clean = label.strip().lower()
    if label_clean not in ALLOWED_LABELS:
        return False, f"Label '{label_clean}' not in allowed set: {sorted(ALLOWED_LABELS)}"
    return True, label_clean


def validate_image_id(image_id: str) -> bool:
    """Validate image ID format to prevent injection."""
    if not isinstance(image_id, str):
        return False
    if len(image_id) > 128:
        return False
    # Allow alphanumeric, hyphens, underscores only
    import re
    return bool(re.match(r'^[a-zA-Z0-9_-]+$', image_id))


