class AnnotatorTrustManager:
    """Manages annotator trust scores to detect and mitigate label flipping attacks."""

    @staticmethod
    def get_trust_score(annotator_id: str) -> float:
        if annotator_id in annotators_db:
            return annotators_db[annotator_id].get('trust_score', 1.0)
        return 1.0

    @staticmethod
    def update_trust_score(annotator_id: str, agreed_with_consensus: bool):
        """Update trust score based on agreement with consensus."""
        if annotator_id not in annotators_db:
            return

        annotator = annotators_db[annotator_id]
        current_score = annotator.get('trust_score', 1.0)
        total = annotator.get('total_annotations', 0)

        # Exponential moving average for trust score
        alpha = 0.1  # Learning rate
        agreement_value = 1.0 if agreed_with_consensus else 0.0
        new_score = current_score * (1 - alpha) + agreement_value * alpha

        # Clamp between 0 and 1
        new_score = max(0.0, min(1.0, new_score))
        annotator['trust_score'] = new_score

        # Flag annotator if trust score drops too low
        if new_score < TRUST_SCORE_THRESHOLD and total > 10:
            annotator['flagged'] = True
            log_audit_event("annotator_flagged_low_trust", {
                "annotator_id": annotator_id,
                "trust_score": new_score,
                "total_annotations": total
            })

    @staticmethod
    def check_annotation_rate(annotator_id: str) -> bool:
        """Check if annotator is submitting at a suspicious rate."""
        if annotator_id not in annotations_db:
            return True

        now = datetime.utcnow()
        one_minute_ago = now - timedelta(minutes=1)

        recent_count = 0
        for image_id, anns in annotations_db.items():
            for ann in anns:
                if ann['annotator_id'] == annotator_id:
                    ann_time = datetime.fromisoformat(ann['timestamp'])
                    if ann_time > one_minute_ago:
                        recent_count += 1

        if recent_count >= ANNOTATION_RATE_LIMIT_PER_MINUTE:
            log_audit_event("suspicious_annotation_rate", {
                "annotator_id": annotator_id,
                "rate": recent_count,
                "threshold": ANNOTATION_RATE_LIMIT_PER_MINUTE
            })
            return False
        return True

    @staticmethod
    def detect_label_flipping_pattern(annotator_id: str) -> bool:
        """
        Detect if an annotator shows patterns consistent with label flipping attacks.
        Returns True if suspicious pattern detected.
        """
        annotator_labels = []
        for image_id, anns in annotations_db.items():
            for ann in anns:
                if ann['annotator_id'] == annotator_id:
                    annotator_labels.append({
                        'image_id': image_id,
                        'label': ann['label'],
                        'timestamp': ann['timestamp']
                    })

        if len(annotator_labels) < 10:
            return False

        # Check disagreement rate with consensus
        disagreements = 0
        total_with_consensus = 0
        for al in annotator_labels:
            if al['image_id'] in aggregated_labels_db:
                total_with_consensus += 1
                consensus = aggregated_labels_db[al['image_id']]['label']
                if al['label'] != consensus:
                    disagreements += 1

        if total_with_consensus > 0:
            disagreement_rate = disagreements / total_with_consensus
            if disagreement_rate > DISAGREEMENT_RATE_THRESHOLD:
                log_audit_event("label_flipping_pattern_detected", {
                    "annotator_id": annotator_id,
                    "disagreement_rate": disagreement_rate,
                    "total_checked": total_with_consensus
                })
                return True

        return False


