class SecureLabelAggregator:
    """
    Aggregates labels using trust-weighted majority voting.
    Mitigates label flipping by weighting votes by annotator trust scores
    and requiring minimum consensus thresholds.
    """

    @staticmethod
    def aggregate_labels(image_id: str) -> Optional[dict]:
        """
        Trust-weighted majority voting with security checks.
        Only considers annotations from non-flagged annotators with sufficient trust.
        """
        if image_id not in annotations_db or not annotations_db[image_id]:
            return None

        annotations = annotations_db[image_id]

        # Filter out annotations from flagged/untrusted annotators
        trusted_annotations = []
        excluded_annotations = []
        for ann in annotations:
            annotator_id = ann['annotator_id']
            if annotator_id not in annotators_db:
                excluded_annotations.append(ann)
                continue

            annotator = annotators_db[annotator_id]
            if annotator.get('flagged', False):
                excluded_annotations.append(ann)
                log_audit_event("annotation_excluded_flagged", {
                    "annotator_id": annotator_id,
                    "image_id": image_id,
                    "label": ann['label']
                })
                continue

            trust_score = annotator.get('trust_score', 1.0)
            if trust_score < TRUST_SCORE_THRESHOLD:
                excluded_annotations.append(ann)
                log_audit_event("annotation_excluded_low_trust", {
                    "annotator_id": annotator_id,
                    "image_id": image_id,
                    "trust_score": trust_score
                })
                continue

            trusted_annotations.append(ann)

        if len(trusted_annotations) < MIN_ANNOTATORS_FOR_CONSENSUS:
            return {
                'label': None,
                'confidence': 0.0,
                'status': 'insufficient_trusted_annotations',
                'trusted_count': len(trusted_annotations),
                'excluded_count': len(excluded_annotations),
                'required': MIN_ANNOTATORS_FOR_CONSENSUS
            }

        # Trust-weighted voting
        weighted_votes: Dict[str, float] = {}
        for ann in trusted_annotations:
            annotator_id = ann['annotator_id']
            label = ann['label']
            trust_score = annotators_db[annotator_id].get('trust_score', 1.0)
            weighted_votes[label] = weighted_votes.get(label, 0.0) + trust_score

        total_weight = sum(weighted_votes.values())
        if total_weight == 0:
            return None

        # Find winning label
        winning_label = max(weighted_votes, key=weighted_votes.get)
        confidence = weighted_votes[winning_label] / total_weight

        # Require minimum confidence
        if confidence < MIN_CONFIDENCE_THRESHOLD:
            log_audit_event("low_confidence_aggregation", {
                "image_id": image_id,
                "confidence": confidence,
                "votes": weighted_votes
            })
            return {
                'label': winning_label,
                'confidence': confidence,
                'status': 'low_confidence',
                'weighted_votes': weighted_votes,
                'trusted_count': len(trusted_annotations),
                'excluded_count': len(excluded_annotations)
            }

        # Update trust scores based on agreement
        for ann in trusted_annotations:
            agreed = ann['label'] == winning_label
            trust_manager.update_trust_score(ann['annotator_id'], agreed)

        result = {
            'label': winning_label,
            'confidence': confidence,
            'status': 'consensus_reached',
            'method': 'trust_weighted_majority_vote',
            'weighted_votes': weighted_votes,
            'trusted_count': len(trusted_annotations),
            'excluded_count': len(excluded_annotations),
            'timestamp': datetime.utcnow().isoformat()
        }

        log_audit_event("label_aggregated", {
            "image_id": image_id,
            "label": winning_label,
            "confidence": confidence,
            "trusted_annotators": len(trusted_annotations),
            "excluded_annotators": len(excluded_annotations)
        })

        return result

    @staticmethod
    def compute_label_integrity_hash(image_id: str, label: str) -> str:
        """Compute HMAC for label integrity verification."""
        message = f"{image_id}:{label}".encode('utf-8')
        return hmac.new(
            app.config['SECRET_KEY'].encode('utf-8') if isinstance(app.config['SECRET_KEY'], str) else app.config['SECRET_KEY'],
            message,
            hashlib.sha256
        ).hexdigest()

    @staticmethod
    def verify_label_integrity(image_id: str, label: str, stored_hash: str) -> bool:
        """Verify label has not been tampered with."""
        expected_hash = SecureLabelAggregator.compute_label_integrity_hash(image_id, label)
        return hmac.compare_digest(expected_hash, stored_hash)


