class SecureTrainingDataPreparer:
    """
    Prepares training data with integrity checks to prevent
    poisoned/flipped labels from entering the training pipeline.
    """

    @staticmethod
    def prepare_training_data() -> List[dict]:
        """
        Only include data points that meet security criteria:
        - Sufficient consensus confidence
        - Label integrity verified
        - No flagged anomalies
        """
        secure_training_data = []

        for image_id, agg_result in aggregated_labels_db.items():
            # Skip if no consensus or low confidence
            if agg_result.get('status') != 'consensus_reached':
                continue

            label = agg_result.get('label')
            confidence = agg_result.get('confidence', 0.0)

            if label is None or confidence < MIN_CONFIDENCE_THRESHOLD:
                continue

            # Verify label is in allowed set
            valid, _ = validate_label(label)
            if not valid:
                log_audit_event("invalid_label_in_training_data", {
                    "image_id": image_id,
                    "label": label
                })
                continue

            # Verify label integrity hash
            integrity_hash = agg_result.get('integrity_hash')
            if integrity_hash:
                if not aggregator.verify_label_integrity(image_id, label, integrity_hash):
                    log_audit_event("label_integrity_check_failed", {
                        "image_id": image_id,
                        "label": label
                    })
                    continue

            # Check that the image exists
            if image_id not in images_db:
                continue

            secure_training_data.append({
                'image_id': image_id,
                'label': label,
                'confidence': confidence,
                'num_annotators': agg_result.get('trusted_count', 0)
            })

        log_audit_event("training_data_prepared", {
            "total_samples": len(secure_training_data),
            "total_aggregated": len(aggregated_labels_db),
            "filtered_out": len(aggregated_labels_db) - len(secure_training_data)
        })

        return secure_training_data

    @staticmethod
    def detect_dataset_poisoning(training_data: List[dict]) -> dict:
        """
        Statistical checks on the training dataset to detect
        potential poisoning attacks (e.g., systematic label flipping).
        """
        if not training_data:
            return {"status": "empty_dataset"}

        label_counts = Counter(d['label'] for d in training_data)
        total = len(training_data)

        # Check for extreme class imbalance that might indicate poisoning
        warnings = []
        for label, count in label_counts.items():
            proportion = count / total
            if proportion > 0.8:
                warnings.append(f"Label '{label}' dominates with {proportion:.1%}")
            elif proportion < 0.01 and total > 100:
                warnings.append(f"Label '{label}' suspiciously rare at {proportion:.1%}")

        # Check average confidence
        avg_confidence = np.mean([d['confidence'] for d in training_data])
        if avg_confidence < 0.7:
            warnings.append(f"Low average confidence: {avg_confidence:.2f}")

        result = {
            "status": "warnings" if warnings else "clean",
            "total_samples": total,
            "label_distribution": dict(label_counts),
            "average_confidence": float(avg_confidence),
            "warnings": warnings
        }

        if warnings:
            log_audit_event("dataset_poisoning_warnings", result)

        return result


