@app.route('/api/register', methods=['POST'])
@limiter.limit("10 per hour")
def register_annotator():
    """Register a new annotator."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    annotator_id = data.get('annotator_id', '').strip()
    password = data.get('password', '')
    role = data.get('role', 'annotator')

    if not annotator_id or not password:
        return jsonify({'error': 'annotator_id and password required'}), 400

    if len(annotator_id) > 64 or len(password) < 8:
        return jsonify({'error': 'Invalid annotator_id length or password too short'}), 400

    if role not in ('annotator', 'admin'):
        role = 'annotator'

    if annotator_id in annotators_db:
        return jsonify({'error': 'Annotator already exists'}), 409

    annotators_db[annotator_id] = {
        'password_hash': generate_password_hash(password),
        'role': role,
        'trust_score': 1.0,
        'flagged': False,
        'total_annotations': 0,
        'created_at': datetime.utcnow().isoformat()
    }

    log_audit_event("annotator_registered", {"annotator_id": annotator_id, "role": role})
    token = generate_token(annotator_id, role)
    return jsonify({'message': 'Registered', 'token': token}), 201


@app.route('/api/login', methods=['POST'])
@limiter.limit("20 per hour")
def login():
    """Authenticate annotator and return JWT."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    annotator_id = data.get('annotator_id', '')
    password = data.get('password', '')

    if annotator_id not in annotators_db:
        return jsonify({'error': 'Invalid credentials'}), 401

    if not check_password_hash(annotators_db[annotator_id]['password_hash'], password):
        log_audit_event("failed_login", {"annotator_id": annotator_id})
        return jsonify({'error': 'Invalid credentials'}), 401

    role = annotators_db[annotator_id]['role']
    token = generate_token(annotator_id, role)
    return jsonify({'token': token}), 200


